yManagerFactory(entityManagerFactory);        return txManager;    &#125;        // 5） JdbcTemplate    @Bean(name = &quot;jdbcTemplateSharding&quot;)    @Primary    public JdbcTemplate jdbcTemplateSharding() &#123;        JdbcTemplate jdbcTemplate = new JdbcTemplate();        jdbcTemplate.setDataSource(primaryDataSource);        return jdbcTemplate;    &#125;&#125;


