手动触发Bean Validation 还可自定义规划并且手动触发校验。注意 MoneyValidator 和 Money 相互一致

自定义Validation注解
import xxx.MoneyValidator;import javax.validation.Constraint;import javax.validation.Payload;import java.lang.annotation.ElementType;import java.lang.annotation.Retention;import java.lang.annotation.RetentionPolicy;import java.lang.annotation.Target;@Target(&#123;ElementType.FIELD, ElementType.METHOD&#125;)@Retention(RetentionPolicy.RUNTIME)@Constraint(validatedBy= MoneyValidator.class)public @interface Money &#123;    String message() default&quot;不是金额形式&quot;;    Class&lt;?&gt;[] groups() default &#123;&#125;;    Class&lt;? extends Payload&gt;[] payload() default &#123;&#125;;&#125;
自定义Validation校验
import xxx.Money;import javax.validation.ConstraintValidator;import javax.validation.ConstraintValidatorContext;import java.util.regex.Pattern;public class MoneyValidator implements ConstraintValidator&lt;Money, String&gt; &#123;    private String moneyReg = &quot;^\\d+(\\.\\d&#123;1,2&#125;)?$&quot;;//表示金额的正则表达式    private Pattern moneyPattern = Pattern.compile(moneyReg);    @Override    public void initialize(Money constraintAnnotation) &#123;        ConstraintValidator.super.initialize(constraintAnnotation);    &#125;    @Override    public boolean isValid(String value, ConstraintValidatorContext constraintValidatorContext) &#123;        if (value == null)            return true;        return moneyPattern.matcher(value).matches();    &#125;&#125;

